package com.example.samlsp.config;

import org.opensaml.security.credential.Credential;
import org.opensaml.security.credential.impl.KeyStoreCredentialResolver;
import org.opensaml.security.x509.BasicX509Credential;
import org.opensaml.security.x509.X509Credential;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.core.io.ResourceLoader;

import java.io.InputStream;
import java.security.KeyStore;
import java.security.cert.CertificateFactory;
import java.security.cert.X509Certificate;
import java.util.HashMap;
import java.util.Map;

@Configuration
public class KeyStoreConfig {

    @Autowired
    private SAMLProperties samlProperties;

    @Autowired
    private ResourceLoader resourceLoader;

    @Bean
    public KeyStore samlKeyStore() throws Exception {
        KeyStore keyStore = KeyStore.getInstance("JKS");
        try (InputStream is = resourceLoader.getResource(samlProperties.getKeystorePath()).getInputStream()) {
            keyStore.load(is, samlProperties.getKeystorePassword().toCharArray());
        }
        return keyStore;
    }

    @Bean
    public X509Credential spCredential(KeyStore samlKeyStore) throws Exception {
        Map<String, String> passwordMap = new HashMap<>();
        passwordMap.put(samlProperties.getKeyAlias(), samlProperties.getKeyPassword());

        KeyStoreCredentialResolver resolver = new KeyStoreCredentialResolver(samlKeyStore, passwordMap);
        Credential credential = resolver.resolveSingle(
                new org.opensaml.security.criteria.UsageCriteria(
                        org.opensaml.security.credential.UsageType.UNSPECIFIED));

        if (credential == null) {
            java.security.PrivateKey privateKey = (java.security.PrivateKey) samlKeyStore.getKey(
                    samlProperties.getKeyAlias(),
                    samlProperties.getKeyPassword().toCharArray());
            X509Certificate cert = (X509Certificate) samlKeyStore.getCertificate(samlProperties.getKeyAlias());
            BasicX509Credential x509Credential = new BasicX509Credential(cert, privateKey);
            x509Credential.setEntityId(samlProperties.getEntityId());
            return x509Credential;
        }

        return (X509Credential) credential;
    }

    @Bean
    public X509Certificate idpCertificate() throws Exception {
        String certPath = samlProperties.getIdp().getCertificatePath();
        if (certPath != null && !certPath.isEmpty()) {
            try (InputStream is = resourceLoader.getResource(certPath).getInputStream()) {
                CertificateFactory cf = CertificateFactory.getInstance("X.509");
                return (X509Certificate) cf.generateCertificate(is);
            }
        }
        return null;
    }

    @Bean
    public X509Credential idpCredential(X509Certificate idpCertificate) {
        if (idpCertificate != null) {
            BasicX509Credential credential = new BasicX509Credential(idpCertificate);
            credential.setEntityId(samlProperties.getIdp().getEntityId());
            return credential;
        }
        return null;
    }
}

