package com.example.samlsp.config;

import com.example.samlsp.security.SAMLAuthenticationFilter;
import com.example.samlsp.security.SAMLAuthenticationProvider;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.security.authentication.AuthenticationManager;
import org.springframework.security.config.annotation.authentication.builders.AuthenticationManagerBuilder;
import org.springframework.security.config.annotation.web.builders.HttpSecurity;
import org.springframework.security.config.annotation.web.configuration.EnableWebSecurity;
import org.springframework.security.web.SecurityFilterChain;
import org.springframework.security.web.authentication.UsernamePasswordAuthenticationFilter;

@Configuration
@EnableWebSecurity
public class SecurityConfig {

    @Autowired
    private SAMLAuthenticationProvider samlAuthenticationProvider;

    @Bean
    public AuthenticationManager authenticationManager(HttpSecurity http) throws Exception {
        AuthenticationManagerBuilder builder = http.getSharedObject(AuthenticationManagerBuilder.class);
        builder.authenticationProvider(samlAuthenticationProvider);
        return builder.build();
    }

    @Bean
    public SAMLAuthenticationFilter samlAuthenticationFilter(AuthenticationManager authenticationManager) {
        SAMLAuthenticationFilter filter = new SAMLAuthenticationFilter("/saml/acs");
        filter.setAuthenticationManager(authenticationManager);
        return filter;
    }

    @Bean
    public SecurityFilterChain securityFilterChain(HttpSecurity http,
                                                    SAMLAuthenticationFilter samlAuthenticationFilter) throws Exception {
        http
                .csrf(csrf -> csrf
                        .ignoringRequestMatchers("/saml/**"))
                .authorizeHttpRequests(auth -> auth
                        .requestMatchers("/saml/**", "/login", "/error", "/health").permitAll()
                        .anyRequest().authenticated())
                .addFilterBefore(samlAuthenticationFilter, UsernamePasswordAuthenticationFilter.class)
                .exceptionHandling(ex -> ex
                        .authenticationEntryPoint((request, response, authException) ->
                                response.sendRedirect("/saml/login")));

        return http.build();
    }
}

