package com.example.samlsp.model;

import org.springframework.security.core.GrantedAuthority;
import org.springframework.security.core.authority.SimpleGrantedAuthority;
import org.springframework.security.core.userdetails.UserDetails;

import java.util.*;

public class SAMLUserDetails implements UserDetails {

    private final String username;
    private final String email;
    private final String firstName;
    private final String lastName;
    private final String nameId;
    private final Map<String, List<String>> attributes;
    private final Collection<GrantedAuthority> authorities;

    public SAMLUserDetails(String nameId, Map<String, List<String>> attributes) {
        this.nameId = nameId;
        this.attributes = attributes != null ? attributes : new HashMap<>();

        this.email = getFirstAttribute("email");
        this.firstName = getFirstAttribute("firstName");
        this.lastName = getFirstAttribute("lastName");
        this.username = email != null ? email : nameId;

        List<GrantedAuthority> auths = new ArrayList<>();
        auths.add(new SimpleGrantedAuthority("ROLE_USER"));

        List<String> roles = this.attributes.get("roles");
        if (roles != null) {
            for (String role : roles) {
                auths.add(new SimpleGrantedAuthority("ROLE_" + role.toUpperCase()));
            }
        }
        this.authorities = Collections.unmodifiableList(auths);
    }

    private String getFirstAttribute(String key) {
        List<String> values = attributes.get(key);
        return (values != null && !values.isEmpty()) ? values.get(0) : null;
    }

    @Override
    public Collection<? extends GrantedAuthority> getAuthorities() { return authorities; }

    @Override
    public String getPassword() { return ""; }

    @Override
    public String getUsername() { return username; }

    @Override
    public boolean isAccountNonExpired() { return true; }

    @Override
    public boolean isAccountNonLocked() { return true; }

    @Override
    public boolean isCredentialsNonExpired() { return true; }

    @Override
    public boolean isEnabled() { return true; }

    public String getEmail() { return email; }
    public String getFirstName() { return firstName; }
    public String getLastName() { return lastName; }
    public String getNameId() { return nameId; }
    public Map<String, List<String>> getAttributes() { return attributes; }
}

