@Service
public class SAMLService {

    private static final Logger logger = LoggerFactory.getLogger(SAMLService.class);

    @Autowired
    private SAMLProperties samlProperties;

    @Autowired
    private X509Credential spCredential;

    @Autowired(required = false)
    @Qualifier("idpCredential")
    private X509Credential idpCredential;

    private final RandomIdentifierGenerationStrategy idGenerator = new RandomIdentifierGenerationStrategy();

    public String buildAuthnRequest() throws Exception {
        AuthnRequest authnRequest = buildAuthnRequestObject();

        if (samlProperties.isAuthnRequestsSigned()) {
            signObject(authnRequest);
        }

        String xml = marshalToString(authnRequest);
        String deflated = deflateAndBase64Encode(xml);
        String encoded = URLEncoder.encode(deflated, StandardCharsets.UTF_8.name());

        String idpSsoUrl = samlProperties.getIdp().getSsoUrl();
        String separator = idpSsoUrl.contains("?") ? "&" : "?";
        return idpSsoUrl + separator + "SAMLRequest=" + encoded;
    }

    public String buildAuthnRequestPostForm() throws Exception {
        AuthnRequest authnRequest = buildAuthnRequestObject();

        if (samlProperties.isAuthnRequestsSigned()) {
            signObject(authnRequest);
        }

        String xml = marshalToString(authnRequest);
        String encoded = Base64.getEncoder().encodeToString(xml.getBytes(StandardCharsets.UTF_8));

        StringBuilder form = new StringBuilder();
        form.append("<!DOCTYPE html><html><body onload=\"document.forms[0].submit()\">");
        form.append("<form method=\"POST\" action=\"").append(samlProperties.getIdp().getSsoUrl()).append("\">");
        form.append("<input type=\"hidden\" name=\"SAMLRequest\" value=\"").append(encoded).append("\"/>");
        form.append("<input type=\"hidden\" name=\"RelayState\" value=\"/\"/>");
        form.append("<noscript><input type=\"submit\" value=\"Continue\"/></noscript>");
        form.append("</form></body></html>");

        return form.toString();
    }

    private AuthnRequest buildAuthnRequestObject() {
        AuthnRequest authnRequest = new AuthnRequestBuilder().buildObject();
        authnRequest.setID("_" + idGenerator.generateIdentifier());
        authnRequest.setIssueInstant(Instant.now());
        authnRequest.setDestination(samlProperties.getIdp().getSsoUrl());
        authnRequest.setProtocolBinding(SAMLConstants.SAML2_POST_BINDING_URI);
        authnRequest.setAssertionConsumerServiceURL(samlProperties.getAcsUrl());
        authnRequest.setIsPassive(false);
        authnRequest.setForceAuthn(false);

        Issuer issuer = new IssuerBuilder().buildObject();
        issuer.setValue(samlProperties.getEntityId());
        authnRequest.setIssuer(issuer);

        NameIDPolicy nameIDPolicy = new NameIDPolicyBuilder().buildObject();
        nameIDPolicy.setFormat(NameIDType.EMAIL);
        nameIDPolicy.setAllowCreate(true);
        authnRequest.setNameIDPolicy(nameIDPolicy);

        RequestedAuthnContext requestedAuthnContext = new RequestedAuthnContextBuilder().buildObject();
        requestedAuthnContext.setComparison(AuthnContextComparisonTypeEnumeration.MINIMUM);

        AuthnContextClassRef authnContextClassRef = new AuthnContextClassRefBuilder().buildObject();
        authnContextClassRef.setURI(AuthnContext.PASSWORD_AUTHN_CTX);
        requestedAuthnContext.getAuthnContextClassRefs().add(authnContextClassRef);
        authnRequest.setRequestedAuthnContext(requestedAuthnContext);

        return authnRequest;
    }

    public Response parseResponse(String base64Response) throws Exception {
        byte[] decoded = Base64.getDecoder().decode(base64Response);
        String xml = new String(decoded, StandardCharsets.UTF_8);

        DocumentBuilderFactory dbf = DocumentBuilderFactory.newInstance();
        dbf.setNamespaceAware(true);
        dbf.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
        dbf.setFeature("http://xml.org/sax/features/external-general-entities", false);
        dbf.setFeature("http://xml.org/sax/features/external-parameter-entities", false);

        Document document = dbf.newDocumentBuilder()
                .parse(new ByteArrayInputStream(xml.getBytes(StandardCharsets.UTF_8)));

        Element element = document.getDocumentElement();
        UnmarshallerFactory unmarshallerFactory = XMLObjectProviderRegistrySupport.getUnmarshallerFactory();
        Unmarshaller unmarshaller = unmarshallerFactory.getUnmarshaller(element);

        if (unmarshaller == null) {
            throw new RuntimeException("Unable to find unmarshaller for SAML Response");
        }

        return (Response) unmarshaller.unmarshall(element);
    }

    public void validateResponse(Response response) throws Exception {
        if (response.getStatus() == null ||
                response.getStatus().getStatusCode() == null ||
                !StatusCode.SUCCESS.equals(response.getStatus().getStatusCode().getValue())) {
            throw new RuntimeException("SAML Response status is not SUCCESS");
        }

        if (response.getAssertions() == null || response.getAssertions().isEmpty()) {
            throw new RuntimeException("No assertions found in SAML Response");
        }

        Assertion assertion = response.getAssertions().get(0);
        validateAssertion(assertion);
    }

    private void validateAssertion(Assertion assertion) throws Exception {
        if (assertion.getConditions() != null) {
            Conditions conditions = assertion.getConditions();

            Instant now = Instant.now();
            if (conditions.getNotBefore() != null && now.isBefore(conditions.getNotBefore())) {
                throw new RuntimeException("Assertion is not yet valid (NotBefore)");
            }
            if (conditions.getNotOnOrAfter() != null && now.isAfter(conditions.getNotOnOrAfter())) {
                throw new RuntimeException("Assertion has expired (NotOnOrAfter)");
            }

            for (AudienceRestriction restriction : conditions.getAudienceRestrictions()) {
                boolean audienceMatch = false;
                for (Audience audience : restriction.getAudiences()) {
                    if (samlProperties.getEntityId().equals(audience.getURI())) {
                        audienceMatch = true;
                        break;
                    }
                }
                if (!audienceMatch) {
                    throw new RuntimeException("Audience restriction validation failed");
                }
            }
        }

        if (assertion.getSubject() != null &&
                assertion.getSubject().getSubjectConfirmations() != null) {
            for (SubjectConfirmation confirmation : assertion.getSubject().getSubjectConfirmations()) {
                SubjectConfirmationData data = confirmation.getSubjectConfirmationData();
                if (data != null) {
                    if (data.getNotOnOrAfter() != null &&
                            Instant.now().isAfter(data.getNotOnOrAfter())) {
                        throw new RuntimeException("Subject confirmation has expired");
                    }
                    if (data.getRecipient() != null &&
                            !samlProperties.getAcsUrl().equals(data.getRecipient())) {
                        throw new RuntimeException("Subject confirmation recipient mismatch");
                    }
                }
            }
        }
    }

    public String extractNameId(Response response) {
        if (response.getAssertions() != null && !response.getAssertions().isEmpty()) {
            Assertion assertion = response.getAssertions().get(0);
            if (assertion.getSubject() != null && assertion.getSubject().getNameID() != null) {
                return assertion.getSubject().getNameID().getValue();
            }
        }
        return null;
    }

    public Map<String, List<String>> extractAttributes(Response response) {
        Map<String, List<String>> attributes = new HashMap<>();

        if (response.getAssertions() != null) {
            for (Assertion assertion : response.getAssertions()) {
                if (assertion.getAttributeStatements() != null) {
                    for (AttributeStatement statement : assertion.getAttributeStatements()) {
                        for (Attribute attribute : statement.getAttributes()) {
                            String name = attribute.getName();
                            List<String> values = new ArrayList<>();
                            for (org.opensaml.core.xml.XMLObject value : attribute.getAttributeValues()) {
                                if (value.getDOM() != null) {
                                    values.add(value.getDOM().getTextContent());
                                }
                            }
                            attributes.put(name, values);
                        }
                    }
                }
            }
        }

        return attributes;
    }

    public String buildLogoutRequest(String nameId, String sessionIndex) throws Exception {
        LogoutRequest logoutRequest = new LogoutRequestBuilder().buildObject();
        logoutRequest.setID("_" + idGenerator.generateIdentifier());
        logoutRequest.setIssueInstant(Instant.now());
        logoutRequest.setDestination(samlProperties.getIdp().getSloUrl());

        Issuer issuer = new IssuerBuilder().buildObject();
        issuer.setValue(samlProperties.getEntityId());
        logoutRequest.setIssuer(issuer);

        NameID nameID = new NameIDBuilder().buildObject();
        nameID.setValue(nameId);
        nameID.setFormat(NameIDType.EMAIL);
        logoutRequest.setNameID(nameID);

        if (sessionIndex != null) {
            SessionIndex sessionIdx = new SessionIndexBuilder().buildObject();
            sessionIdx.setValue(sessionIndex);
            logoutRequest.getSessionIndexes().add(sessionIdx);
        }

        if (samlProperties.isAuthnRequestsSigned()) {
            signObject(logoutRequest);
        }

        String xml = marshalToString(logoutRequest);
        String deflated = deflateAndBase64Encode(xml);
        String encoded = URLEncoder.encode(deflated, StandardCharsets.UTF_8.name());

        String sloUrl = samlProperties.getIdp().getSloUrl();
        String separator = sloUrl.contains("?") ? "&" : "?";
        return sloUrl + separator + "SAMLRequest=" + encoded;
    }

    public String generateSPMetadata() throws Exception {
        EntityDescriptor entityDescriptor = new EntityDescriptorBuilder().buildObject();
        entityDescriptor.setEntityID(samlProperties.getEntityId());

        SPSSODescriptor spDescriptor = new SPSSODescriptorBuilder().buildObject();
        spDescriptor.setWantAssertionsSigned(samlProperties.isWantAssertionsSigned());
        spDescriptor.setAuthnRequestsSigned(samlProperties.isAuthnRequestsSigned());
        spDescriptor.addSupportedProtocol(SAMLConstants.SAML20P_NS);

        // Signing key descriptor
        KeyDescriptor signingKeyDescriptor = buildKeyDescriptor(
                org.opensaml.security.credential.UsageType.SIGNING);
        spDescriptor.getKeyDescriptors().add(signingKeyDescriptor);

        // Encryption key descriptor
        KeyDescriptor encryptionKeyDescriptor = buildKeyDescriptor(
                org.opensaml.security.credential.UsageType.ENCRYPTION);
        spDescriptor.getKeyDescriptors().add(encryptionKeyDescriptor);

        // NameID formats
        NameIDFormat emailFormat = new NameIDFormatBuilder().buildObject();
        emailFormat.setURI(NameIDType.EMAIL);
        spDescriptor.getNameIDFormats().add(emailFormat);

        NameIDFormat persistentFormat = new NameIDFormatBuilder().buildObject();
        persistentFormat.setURI(NameIDType.PERSISTENT);
        spDescriptor.getNameIDFormats().add(persistentFormat);

        // ACS
        AssertionConsumerService acs = new AssertionConsumerServiceBuilder().buildObject();
        acs.setBinding(SAMLConstants.SAML2_POST_BINDING_URI);
        acs.setLocation(samlProperties.getAcsUrl());
        acs.setIndex(0);
        acs.setIsDefault(true);
        spDescriptor.getAssertionConsumerServices().add(acs);

        // SLO
        SingleLogoutService slo = new SingleLogoutServiceBuilder().buildObject();
        slo.setBinding(SAMLConstants.SAML2_REDIRECT_BINDING_URI);
        slo.setLocation(samlProperties.getSloUrl());
        spDescriptor.getSingleLogoutServices().add(slo);

        entityDescriptor.getRoleDescriptors().add(spDescriptor);

        return marshalToString(entityDescriptor);
    }

    private KeyDescriptor buildKeyDescriptor(org.opensaml.security.credential.UsageType usageType) throws Exception {
        KeyDescriptor keyDescriptor = new KeyDescriptorBuilder().buildObject();
        keyDescriptor.setUse(usageType);

        KeyInfo keyInfo = new KeyInfoBuilder().buildObject();
        X509Data x509Data = new X509DataBuilder().buildObject();
        org.opensaml.xmlsec.signature.X509Certificate x509Cert =
                new X509CertificateBuilder().buildObject();

        X509Certificate cert = spCredential.getEntityCertificate();
        String certBase64 = Base64.getEncoder().encodeToString(cert.getEncoded());
        x509Cert.setValue(certBase64);

        x509Data.getX509Certificates().add(x509Cert);
        keyInfo.getX509Datas().add(x509Data);
        keyDescriptor.setKeyInfo(keyInfo);

        return keyDescriptor;
    }

    private void signObject(org.opensaml.saml.common.SignableSAMLObject signable) throws Exception {
        Signature signature = new SignatureBuilder().buildObject();
        signature.setSigningCredential(spCredential);
        signature.setSignatureAlgorithm(SignatureConstants.ALGO_ID_SIGNATURE_RSA_SHA256);
        signature.setCanonicalizationAlgorithm(SignatureConstants.ALGO_ID_C14N_EXCL_OMIT_COMMENTS);

        signable.setSignature(signature);

        MarshallerFactory marshallerFactory = XMLObjectProviderRegistrySupport.getMarshallerFactory();
        Marshaller marshaller = marshallerFactory.getMarshaller(signable);
        marshaller.marshall(signable);

        Signer.signObject(signature);
    }

    private String marshalToString(org.opensaml.core.xml.XMLObject xmlObject) throws Exception {
        MarshallerFactory marshallerFactory = XMLObjectProviderRegistrySupport.getMarshallerFactory();
        Marshaller marshaller = marshallerFactory.getMarshaller(xmlObject);

        if (marshaller == null) {
            throw new RuntimeException("Unable to find marshaller for: " + xmlObject.getElementQName());
        }

        Element element = marshaller.marshall(xmlObject);
        TransformerFactory tf = TransformerFactory.newInstance();
        Transformer transformer = tf.newTransformer();
        StringWriter writer = new StringWriter();
        transformer.transform(new DOMSource(element), new StreamResult(writer));
        return writer.toString();
    }

    private String deflateAndBase64Encode(String input) throws Exception {
        ByteArrayOutputStream baos = new ByteArrayOutputStream();
        Deflater deflater = new Deflater(Deflater.DEFLATED, true);
        DeflaterOutputStream dos = new DeflaterOutputStream(baos, deflater);
        dos.write(input.getBytes(StandardCharsets.UTF_8));
        dos.close();
        return Base64.getEncoder().encodeToString(baos.toByteArray());
    }
}

