// security/SAMLAuthenticationProvider.java
// ==========================================
package com.example.samlsp.security;

import com.example.samlsp.model.SAMLAuthenticationToken;
import com.example.samlsp.model.SAMLUserDetails;
import com.example.samlsp.service.SAMLService;
import org.opensaml.saml.saml2.core.Response;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.security.authentication.AuthenticationProvider;
import org.springframework.security.authentication.AuthenticationServiceException;
import org.springframework.security.core.Authentication;
import org.springframework.security.core.AuthenticationException;
import org.springframework.stereotype.Component;

import java.util.List;
import java.util.Map;

@Component
public class SAMLAuthenticationProvider implements AuthenticationProvider {

    private static final Logger logger = LoggerFactory.getLogger(SAMLAuthenticationProvider.class);

    @Autowired
    private SAMLService samlService;

    @Override
    public Authentication authenticate(Authentication authentication) throws AuthenticationException {
        SAMLAuthenticationToken token = (SAMLAuthenticationToken) authentication;
        String samlResponse = token.getSamlResponse();

        try {
            Response response = samlService.parseResponse(samlResponse);
            samlService.validateResponse(response);

            String nameId = samlService.extractNameId(response);
            if (nameId == null || nameId.isEmpty()) {
                throw new AuthenticationServiceException("NameID not found in SAML Response");
            }

            Map<String, List<String>> attributes = samlService.extractAttributes(response);

            SAMLUserDetails userDetails = new SAMLUserDetails(nameId, attributes);

            logger.info("Successfully authenticated SAML user: {}", nameId);

            return new SAMLAuthenticationToken(userDetails, userDetails.getAuthorities());

        } catch (AuthenticationException e) {
            throw e;
        } catch (Exception e) {
            logger.error("SAML authentication failed", e);
            throw new AuthenticationServiceException("SAML authentication failed: " + e.getMessage(), e);
        }
    }

    @Override
    public boolean supports(Class<?> authentication) {
        return SAMLAuthenticationToken.class.isAssignableFrom(authentication);
    }
}

