// service/SAMLSessionService.java
// ==========================================
package com.example.samlsp.service;

import org.springframework.stereotype.Service;

import java.util.Map;
import java.util.concurrent.ConcurrentHashMap;

@Service
public class SAMLSessionService {

    private final Map<String, SAMLSessionInfo> sessions = new ConcurrentHashMap<>();

    public void storeSession(String sessionId, String nameId, String samlSessionIndex) {
        sessions.put(sessionId, new SAMLSessionInfo(nameId, samlSessionIndex));
    }

    public SAMLSessionInfo getSession(String sessionId) {
        return sessions.get(sessionId);
    }

    public void removeSession(String sessionId) {
        sessions.remove(sessionId);
    }

    public static class SAMLSessionInfo {
        private final String nameId;
        private final String samlSessionIndex;

        public SAMLSessionInfo(String nameId, String samlSessionIndex) {
            this.nameId = nameId;
            this.samlSessionIndex = samlSessionIndex;
        }

        public String getNameId() { return nameId; }
        public String getSamlSessionIndex() { return samlSessionIndex; }
    }
}

