// controller/SAMLController.java
// ==========================================
package com.example.samlsp.controller;

import com.example.samlsp.config.SAMLProperties;
import com.example.samlsp.model.SAMLUserDetails;
import com.example.samlsp.service.SAMLService;
import com.example.samlsp.service.SAMLSessionService;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.http.MediaType;
import org.springframework.http.ResponseEntity;
import org.springframework.security.core.Authentication;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.stereotype.Controller;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.ResponseBody;

import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;
import javax.servlet.http.HttpSession;
import java.io.IOException;

@Controller
@RequestMapping("/saml")
public class SAMLController {

    private static final Logger logger = LoggerFactory.getLogger(SAMLController.class);

    @Autowired
    private SAMLService samlService;

    @Autowired
    private SAMLProperties samlProperties;

    @Autowired
    private SAMLSessionService sessionService;

    @GetMapping("/login")
    public void initiateLogin(HttpServletResponse response) throws Exception {
        logger.info("Initiating SAML SSO login");
        String redirectUrl = samlService.buildAuthnRequest();
        response.sendRedirect(redirectUrl);
    }

    @GetMapping("/login/post")
    @ResponseBody
    public String initiateLoginPost() throws Exception {
        logger.info("Initiating SAML SSO login via POST binding");
        return samlService.buildAuthnRequestPostForm();
    }

    @GetMapping(value = "/metadata", produces = MediaType.APPLICATION_XML_VALUE)
    @ResponseBody
    public String metadata() throws Exception {
        logger.info("Serving SP metadata");
        return samlService.generateSPMetadata();
    }

    @GetMapping("/logout")
    public void initiateLogout(HttpServletRequest request, HttpServletResponse response) throws Exception {
        logger.info("Initiating SAML SLO");

        Authentication auth = SecurityContextHolder.getContext().getAuthentication();
        String nameId = null;
        String sessionIndex = null;

        if (auth != null && auth.getPrincipal() instanceof SAMLUserDetails) {
            SAMLUserDetails user = (SAMLUserDetails) auth.getPrincipal();
            nameId = user.getNameId();
        }

        HttpSession session = request.getSession(false);
        if (session != null) {
            SAMLSessionService.SAMLSessionInfo sessionInfo =
                    sessionService.getSession(session.getId());
            if (sessionInfo != null) {
                sessionIndex = sessionInfo.getSamlSessionIndex();
                nameId = sessionInfo.getNameId();
            }
            sessionService.removeSession(session.getId());
            session.invalidate();
        }

        SecurityContextHolder.clearContext();

        if (nameId != null && samlProperties.getIdp().getSloUrl() != null) {
            String logoutUrl = samlService.buildLogoutRequest(nameId, sessionIndex);
            response.sendRedirect(logoutUrl);
        } else {
            response.sendRedirect("/login");
        }
    }

    @GetMapping("/slo")
    public void handleSLOResponse(HttpServletRequest request, HttpServletResponse response) throws IOException {
        logger.info("Received SLO response from IdP");

        HttpSession session = request.getSession(false);
        if (session != null) {
            sessionService.removeSession(session.getId());
            session.invalidate();
        }
        SecurityContextHolder.clearContext();

        response.sendRedirect("/login?logout=true");
    }

    @PostMapping("/slo")
    public void handleSLORequest(HttpServletRequest request, HttpServletResponse response) throws IOException {
        logger.info("Received SLO request from IdP");

        HttpSession session = request.getSession(false);
        if (session != null) {
            sessionService.removeSession(session.getId());
            session.invalidate();
        }
        SecurityContextHolder.clearContext();

        response.sendRedirect("/login?logout=true");
    }
}

