package com.example.samlsp.controller;

import com.example.samlsp.model.SAMLUserDetails;
import org.springframework.security.core.Authentication;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RestController;

import java.util.HashMap;
import java.util.Map;

@RestController
public class HomeController {

    @GetMapping("/")
    public Map<String, Object> home() {
        Map<String, Object> result = new HashMap<>();
        Authentication auth = SecurityContextHolder.getContext().getAuthentication();

        if (auth != null && auth.getPrincipal() instanceof SAMLUserDetails) {
            SAMLUserDetails user = (SAMLUserDetails) auth.getPrincipal();
            result.put("authenticated", true);
            result.put("username", user.getUsername());
            result.put("email", user.getEmail());
            result.put("firstName", user.getFirstName());
            result.put("lastName", user.getLastName());
            result.put("nameId", user.getNameId());
            result.put("attributes", user.getAttributes());
            result.put("authorities", user.getAuthorities());
        } else {
            result.put("authenticated", false);
            result.put("message", "Please login via /saml/login");
        }

        return result;
    }

    @GetMapping("/health")
    public Map<String, String> health() {
        Map<String, String> status = new HashMap<>();
        status.put("status", "UP");
        status.put("service", "SAML Service Provider");
        return status;
    }

    @GetMapping("/login")
    public Map<String, String> loginPage() {
        Map<String, String> result = new HashMap<>();
        result.put("message", "Please use /saml/login to initiate SSO");
        result.put("ssoUrl", "/saml/login");
        result.put("metadataUrl", "/saml/metadata");
        return result;
    }
}

